                date_part = parts[-1].strip()
                if is_spring_2022(date_part):
                    target_projects.add(current_project)

        # Buffer line update
        if not '(cid:190)' in line and not '(cid:131)' in line:
            buffer_line = line

# Matching
total_funding = 0
